function spireOverload(...funcs) {
    const defaultFunc = funcs[0];
    const map = funcs.reduce((pre, cur) => {
        const key = getOverloadKeyFromFunc(cur);
        pre.set(key, cur);
        return pre;
    }, new Map());

    return function(...args) {
        if (args.length != 1) {
            return defaultFunc.apply(this, args);
        }
        else if (typeof args[0] !== 'object' || args[0] === null) {
            return defaultFunc.apply(this, args);
        }
        var key = Object.keys(args[0]).join('');
        if (map.get(key) == null) {
            console.log(`${key} not in Overload map. call failed. map's key list:' `);
            map.forEach((k, v) => {
                console.error(`${v}`)
            });
        }
        var vals = Object.values(args[0]);
        return map.get(key)?.apply(this, vals);
    }
}
function getOverloadKeyFromFunc(func) {
    const paramString = func.toString().split('(')[1].split(')')[0];
    const keys = paramString.split(',').map(param => param.trim().split(' ')[0]);
    return keys.join('');
}


