//Pointer to object array ,test success!
function getObjectArrayFromIntPtrT(ptr, obj) {
    let result = [];
    let i = 0;
    const size = Module.getValue(ptr, 'i32');
    if (size < 10) {
        while (i < size) {
            let currentPtr = Module.getValue(ptr + (i * 2 + 1) * 4, 'i32');
            let currentObject = obj.createNewObject(currentPtr);
            result.push(currentObject);
            i++;
        }
    } else {
        const strPtr = Module.getValue(ptr + 4, 'i32');
        while (i < size) {
            let currentPtr = Module.getValue(strPtr + i * 4, 'i32');
            let currentObject = obj.createNewObject(currentPtr);
            result.push(currentObject);
            i++;
        }
    }
    return result;
}
