function getSpireStringArrayPtr(stringArray){
    let arrayPointer = Module._malloc(stringArray.length * 8);
    for (let i = 0; i < stringArray.length; i++) {
        let len = Module.lengthBytesUTF8(stringArray[i]) + 1;
        let strPtr = Module._malloc(len);
        Module.stringToUTF8(stringArray[i], strPtr, len);
        Module.setValue(arrayPointer + i * 8, strPtr, 'i64');
    }
    return arrayPointer;
}
function spireFreeStringArrayPtr(ptr,size){
    for (let i = 0; i < size; i++) {
        let strPtr = Module.getValue(ptr + i * 8, 'i64');
        Module._free(Number(strPtr));
    }
    Module._free(ptr);
}

