spirepdf["FetchFileToVFS"] = SpireLoadRemoteFile;

function copyLocalFileToVFS(localFilePath, vfsPath) {
    const data = fs.readFileSync(localFilePath);
    FS.writeFile(vfsPath, data);
}
function copyLocalPathToVFS(localPath, vfsPath) {
    const items = fs.readdirSync(localPath);

    try {
        FS.analyzePath(vfsPath).exists || FS.mkdirTree(vfsPath);
    } catch (e) {
        if (e.errno !== 20) { // EEXIST error
            throw e;
        }
    }

    items.forEach(item => {
        const localItemPath = nodePath.join(localPath, item);
        const vfsItemPath = vfsPath + item;

        const stats = fs.statSync(localItemPath);

        if (stats.isFile()) {
            const data = fs.readFileSync(localItemPath);
            FS.writeFile(vfsItemPath, data);
        } else if (stats.isDirectory()) {
            copyLocalFilesToVFS(localItemPath, vfsItemPath);
        }
    });
}
function checkAndCreateDirectory(path) {
    const dirPath = nodePath.dirname(nodePath.resolve(path));
    if (!fs.existsSync(dirPath)) {
        fs.mkdirSync(dirPath, { recursive: true });
    } else {
    }
}
function copyFileFromFSToLocalStorage(vfsPath, localPath) {
    if (typeof FS === 'undefined') {
        console.warn('not found Emscripten FS module');
        return;
    }

    if (!FS.analyzePath(vfsPath).exists) {
        console.error(`file ${vfsPath} not found in vfs`);
        return;
    }
    checkAndCreateDirectory(localPath)

    const fileBuffer = FS.readFile(vfsPath, { encoding: 'binary' });

    fs.writeFileSync(localPath, fileBuffer, 'binary');
}
function joinPath(base, name) {
    return (base + '/' + name).replace(/\/+/g, '/');
}
function copyDirectoryFromFSToLocalStorage(vfsPath, localPath) {
    if (typeof FS === 'undefined') {
        console.warn('Not found Emscripten FS module');
        return;
    }

    if (!FS.analyzePath(vfsPath).exists) {
        console.error(`Directory ${vfsPath} not found in vfs`);
        return;
    }

    if (!fs.existsSync(localPath)) {
        fs.mkdirSync(localPath, { recursive: true });
    }

    const contents = FS.readdir(vfsPath);

    for (const item of contents) {
        if (item === '.' || item === '..') continue;

        const vfsItemPath = joinPath(vfsPath, item);
        const localItemPath = nodePath.join(localPath, item);
        const stat = FS.stat(vfsItemPath);

        if (FS.isDir(stat.mode)) {
            copyDirectoryFromFSToLocalStorage(vfsItemPath, localItemPath);
        } else {
            const fileBuffer = FS.readFile(vfsItemPath, { encoding: 'binary' });
            fs.writeFileSync(localItemPath, fileBuffer, 'binary');
        }
    }
}
