function SpireMixin(target, ...sources) {
    sources.forEach(source => {
      for (let key in source) {
        if (!target.hasOwnProperty(key)) {
          target[key] = source[key];
        } else {
          /*console.warn(`Property or method "${key}" already exists in target object. Skipping mixin.`);*/
        }
      }
    });
    return target;
  }

